// MARK: - API Models

private struct ListingResponse: Codable {
    let id: String
    let title: String
    let description: String?
    let address: String
    let price: Int
    let imageUrl: String?
    let sqft: Int?
    let bedrooms: Int?
    let bathrooms: Int?
    let confidenceScore: Int?
    let latitude: Double?
    let longitude: Double?
    let photos: [PhotoResponse]?
