    private func confidenceLabelAndColor(score: Int?) -> (String, Color) {
        guard let s = score else { return ("Pending", .orange) }
        if s >= 85 { return ("Verified", .green) }
        if s >= 60 { return ("Pending", .orange) }
        return ("Low", .red)
