                    .scaledToFill()
            case .failure:
                Color(.tertiarySystemFill)
            default:
                ProgressView()
            }
        }
        .frame(height: 220)
        .clipped()
        .clipShape(RoundedRectangle(cornerRadius: 12))
        .tag(tag)
    }

    private var photoCarousel: some View {
        TabView {
            carouselImage(urlString: Self.photo1, tag: 0)
            carouselImage(urlString: Self.photo2, tag: 1)
